const results = $input.all();

if (!results || results.length === 0 || !results[0].json.slug) {
  return [{ json: { has_data: false, spokes: [] } }];
}

const spokes = results.map(r => ({
  slug: r.json.slug,
  name: r.json.name,
  description: r.json.description,
  icon: r.json.icon || '🔌',
  category: r.json.category,
  plugin_id: r.json.plugin_id,
  tags: r.json.tags || []
}));

return [{ json: { has_data: true, spokes: spokes, count: spokes.length } }];

